 */
std::tuple<int, int, int> test_batch_execution(int initialA,
                                               int initialB,
                                               int nonBatchA,
                                               int nonBatchB,
                                               int batchA,
                                               int batchB) {
    using namespace reaction;

    // 1. Create reactive variables
    auto a = var(initialA);
    auto b = var(initialB);

    // 2. Create variable to track recomputation count
    int recomputeCount = 0;

    // 3. Create calculation that sums a and b
    auto sumCalc = calc([&]() {
        recomputeCount++;  // Track recomputation
        return a() + b();
    });

    // 4. Perform non-batch updates
    a.value(nonBatchA);
    b.value(nonBatchB);

    // 5. Record recompute count after non-batch updates
    int countAfterNonBatch = recomputeCount;

    // 6. Create batch context
    auto batchContext = batch([&]() {
        // 7. Execute batch updates
        a.value(batchA);
        b.value(batchB);
    });

    // 8. Execute batch
    batchContext.execute();

    // 9. Record recompute count after batch updates
    int countAfterBatch = recomputeCount;

    // 10. Return final sum and counts
    return std::make_tuple(sumCalc(), countAfterNonBatch, countAfterBatch);
}

}  // namespace test_reaction
