  EXPECT_TRUE(snapshot.batchActiveInBatchExeGuard);

  EXPECT_FALSE(snapshot.trackingActiveAfter);
  EXPECT_FALSE(snapshot.batchActiveAfter);
  EXPECT_FALSE(snapshot.batchFunActiveAfter);
}

}  // namespace test_reaction

