  // C'       = c + 1
  // sum'     = (a + 1) + b
  // negated' = -((a + 1) + b)
  // chained' = -((a + 1) + b) * (c + 1)
  EXPECT_EQ(snapshot.updatedSum, (a + 1) + b);
  EXPECT_EQ(snapshot.updatedNegatedSum, -((a + 1) + b));
  EXPECT_EQ(snapshot.updatedChainedValue,
            -((a + 1) + b) * (c + 1));
